void ROM_lstm_pruned16_Reset(float *h, float *c) {
    for (int i = 0; i < 16; i++) { h[i] = 0.f; c[i] = 0.f; }
}

float ROM_lstm_pruned16_Step(const float *x, float *h, float *c) {
    float g[64];
    int i, j;
    for (i = 0; i < 64; i++) {
        float v = BIH_lstm_pruned16[i] + BHH_lstm_pruned16[i];
        for (j = 0; j < 3; j++) v += WIH_lstm_pruned16[i*3+j] * x[j];
        for (j = 0; j < 16; j++) v += WHH_lstm_pruned16[i*16+j] * h[j];
        g[i] = v;
    }
    for (i = 0; i < 16; i++) {
        float ig = 1.f/(1.f+expf(-g[i]));
        float fg = 1.f/(1.f+expf(-g[16+i]));
        float gg = tanhf(g[32+i]);
        float og = 1.f/(1.f+expf(-g[48+i]));
        c[i] = fg*c[i] + ig*gg;
        h[i] = og*tanhf(c[i]);
    }
    float y = BFC_lstm_pruned16;
    for (i = 0; i < 16; i++) y += WFC_lstm_pruned16[i]*h[i];
    return y;
}
